import*as Schema from"../schema.js";import*as Instance from"../instance.js";import Validation from"./validation.js";import{fromEpsilon,fromSchema,closure,zeroOrOne,oneOrMore,concat,union}from"../nfa.js";const id="https://json-schema.org/keyword/itemPattern",experimental=!0,compile=async(e,t)=>{const r=[[]];let o=r[0];for await(const a of Schema.iter(e))if(Schema.typeOf(a,"string")){var n=Schema.value(a);if("*"===n)o.push(closure(o.pop()));else if("?"===n)o.push(zeroOrOne(o.pop()));else if("+"===n)o.push(oneOrMore(o.pop()));else{if("|"!==n)throw Error("Unsupported pattern syntax: "+n);o=[],r.push(o)}}else{n=Schema.typeOf(a,"array")?compile(a,t):fromSchema(await Validation.compile(a,t));o.push(await n)}return 0===Schema.length(e)?fromEpsilon():r.map(e=>e.reduce(concat)).reduce(union)},interpret=(e,t,r,o,n)=>{if(!Instance.typeOf(t,"array"))return!0;let a=[];addNextState(e.start,a,[]);for(const p of Instance.iter(t)){var i=[];for(const c of a){var s=transition(c.transition,p,r,o,n);s&&addNextState(s,i,[])}a=i}return Boolean(a.find(e=>e.isEnd))},addNextState=(e,t,r)=>{if(e.epsilonTransitions.length)for(const o of e.epsilonTransitions)r.find(e=>e===o)||(r.push(o),addNextState(o,t,r));else t.push(e)},transition=(e,t,r,o,n)=>{for(const a in e)if(Validation.interpret(a,t,r,o,n))return e[a]};export default{id:id,experimental:experimental,compile:compile,interpret:interpret};